Given the following Python class that implements a Least Recently Used (LRU) cache using a dictionary and a doubly linked list, identify any bugs, suggest refactors for readability, and add type annotations:

class LRUCache:
    def __init__(self, cap):
        self.cap = cap
        self.cache = {}
        self.head, self.tail = Node(0,0), Node(0,0)
        self.head.next = self.tail
        self.tail.prev = self.head
    def get(self, key):
        if key in self.cache:
            self.remove(self.cache[key])
            self.insert(self.cache[key])
            return self.cache[key].val
        return -1

